SELECT count(*) FROM hm_query.wms_inventory_with_product_flat

    AND warehouse_id = #{warehouseId}
    AND product_id = #{productId}
    AND sku = #{sku}
    AND stm_state = #{stateId}
    AND is_low_stock = true
    AND (
        sku LIKE CONCAT('%', #{q}, '%')
        OR product_name LIKE CONCAT('%', #{q}, '%')
        OR brand LIKE CONCAT('%', #{q}, '%')
        OR warehouse_name LIKE CONCAT('%', #{q}, '%')
        OR warehouse_code LIKE CONCAT('%', #{q}, '%')
    )

